/bin/bash -lc "PYTHONDONTWRITEBYTECODE=1 python3 - <<'PY'
from pathlib import Path
from types import SimpleNamespace

def load(path):
    ns = {}
    exec(Path(path).read_text(), ns)
    return ns

routes = load('app/routes.py')
try:
    routes['agent_run'](SimpleNamespace(planexecution_phase='old', domain_context=None, run_mode=None))
except Exception as e:
    print('agent_run-default:', type(e).__name__, str(e))

factory = load('app/factory.py')['factory']
for label, args in [('authority-default', (None, None)), ('legacy-execute', (None, 'execute'))]:
    try:
        factory(*args)
    except Exception as e:
        print(label + ':', type(e).__name__, str(e))
